* PROD -- producer demo (writes one item per ENTER to a TS queue).
MAP PROD1 SIZE 24x80
  FIELD AT 0,0  LEN 24 PROT BRIGHT COLOR=BLUE   "TS queue producer (PROD)"
  FIELD AT 0,60 LEN 5  PROT COLOR=BLUE          "TERM="
  INPUT TERMID  AT 0,65 LEN 8  PROT COLOR=BLUE
  FIELD AT 4,0  LEN 6  PROT                     "Queue:"
  INPUT QNAME   AT 4,8  LEN 16 UNDERSCORE COLOR=GREEN
  STOP          AT 4,25
  FIELD AT 6,0  LEN 8  PROT                     "Payload:"
  INPUT PAYLOAD AT 6,9  LEN 60 UNDERSCORE COLOR=GREEN
  STOP          AT 6,70
  INPUT MSG     AT 18,0 LEN 78 PROT BRIGHT COLOR=RED
  FIELD AT 22,0 LEN 50 PROT COLOR=BLUE          "ENTER=Write  PF3=Exit"
  CURSOR        AT QNAME
ENDMAP
